'use client'

import { useEffect, useState } from 'react'
import Link from 'next/link'
import { supabase } from '../../lib/supabase'
import { jsPDF } from 'jspdf'
import autoTable from 'jspdf-autotable'

export default function Operaciones() {
  const [operaciones, setOperaciones] = useState<any[]>([])
  const [cargando, setCargando] = useState(true)

  const cargarOperaciones = async () => {
    const { data, error } = await supabase
      .from('operaciones')
      .select('*')
      .order('created_at', { ascending: false })

    if (!error && data) {
      setOperaciones(data)
    }
    setCargando(false)
  }

  useEffect(() => {
    cargarOperaciones()
  }, [])

  // FUNCIÓN PARA ELIMINAR 🗑️
  const eliminarOperacion = async (id: any) => {
    const confirmar = window.confirm("¿Estás segura de que querés eliminar esta operación definitivamente?")
    if (!confirmar) return;

    const { error } = await supabase.from('operaciones').delete().eq('id', id);

    if (error) {
      alert("Hubo un error al eliminar: " + error.message)
    } else {
      cargarOperaciones();
    }
  }

  // FUNCIÓN ESTRELLA: GENERAR PDF 📄✨ - VERSIÓN CON TU LOGO REAL
  const generarPDF = (op: any) => {
    // 1. Creamos un documento en blanco (A4)
    const doc = new jsPDF()

    // --- 2. ENCABEZADO CON TU LOGO REAL ---
    const logoX = 14;
    const logoY = 16;
    
    // 👇👇👇 MAJO, PEGÁ ACÁ ABAJO TU CÓDIGO BASE64 GIGANTE (entre las comillas simples) 👇👇👇
    
    const logoBase64 = 'data:image/jpeg;base64,';
    // He puesto una cadena Base64 genérica (un rectángulo púrpura) para que puedas probar la ubicación.
    // Reemplazala por la tuya.

    // Dibujamos la imagen real
    try {
      // Dimensiones de tu logo (Podes ajustar 40 de ancho x 16 de alto si queda mal)
      doc.addImage(logoBase64, 'PNG', logoX, logoY, 40, 16);
    } catch (e) {
      console.error("Error cargando el logo real, usando fallback circular.", e);
      // Fallback sutil si falla la imagen real (tu logo circular viejo hecho con código)
      doc.setFillColor(147, 51, 234).circle(logoX + 8, logoY + 8, 8, 'F');
      doc.setFont('helvetica', 'bold').setFontSize(14).setTextColor(255, 255, 255).text('CC', logoX + 8, logoY + 11.5, { align: 'center' });
    }
    
    // --- RESTO DEL ENCABEZADO PULIDO ---
    // Ajustamos la posición del texto para que no pise el logo real (logoX + 45)
    doc.setFont('helvetica', 'bold')
    doc.setFontSize(24)
    doc.setTextColor(30, 41, 59) // Slate-800
    doc.text('CARRIZO', logoX + 45, logoY + 8)
    doc.setTextColor(147, 51, 234) // Púrpura
    doc.text('Comex', logoX + 91, logoY + 8)
    
    doc.setFont('helvetica', 'normal')
    doc.setFontSize(10)
    doc.setTextColor(100, 100, 100) // Gris oscuro
    doc.text('Especialistas en Comercio Exterior', logoX + 45, logoY + 14)
    
    // Fecha y ID de la Proforma (Desplazado a la derecha)
    const docWidth = doc.internal.pageSize.getWidth();
    doc.text(`Fecha de emisión: ${new Date().toLocaleDateString('es-AR')}`, docWidth - 14, logoY + 8, { align: 'right' });
    doc.text(`Proforma ID: ${op.id.substring(0,8)}`, docWidth - 14, logoY + 14, { align: 'right' });

    // Línea separadora pulida (más delgada y sutil)
    doc.setDrawColor(220, 220, 220)
    doc.setLineWidth(0.5)
    doc.line(14, logoY + 20, docWidth - 14, logoY + 20)

    // --- TÍTULO DE LA SECCIÓN ---
    doc.setFontSize(14)
    doc.setTextColor(30, 41, 59) // Slate-800
    doc.text(`Resumen de Operación de ${op.tipo}`, 14, logoY + 30)

    // --- 3. TABLA 1: DATOS DEL CLIENTE Y LA CARGA (Estilo Gris/Blanco) ---
    autoTable(doc, {
      startY: logoY + 36,
      theme: 'striped',
      headStyles: { fillColor: [241, 245, 249], textColor: [15, 23, 42], fontStyle: 'bold' }, // Slate-100 y Slate-900
      bodyStyles: { textColor: [71, 85, 105] }, // Slate-500
      styles: { lineColor: [230, 230, 230], lineWidth: 0.1 },
      body: [
        ['Cliente / Razón Social', { content: op.cliente || 'Sin especificar', styles: { fontStyle: 'bold', textColor: [30, 41, 59] } }],
        ['CUIT', op.cuit || 'Sin especificar'],
        ['Domicilio Operativo', op.domicilio || 'Sin especificar'],
        ['Mercadería', op.producto || 'Sin especificar'],
        ['Posición NCM (IA)', { content: op.posicion_ncm || 'Pendiente', styles: { fontStyle: 'bold', textColor: [147, 51, 234] } }],
        ['Valor FOB Estimado', `USD ${op.fob || 0}`],
        ['Peso (Neto / Bruto)', `${op.peso_neto || 0} kg / ${op.peso_bruto || 0} kg`]
      ],
    })

    // --- 4. TABLA 2: CHECKLIST DOCUMENTAL (El estado de situación con colores) ---
    const alturaActual = (doc as any).lastAutoTable.finalY + 14

    doc.setFontSize(12)
    doc.setTextColor(30, 41, 59)
    doc.text('Estado de Documentación Logística:', 14, alturaActual)
// Función para obtener texto y estilo de estado
const getEstadoData = (estado: boolean): any => {
  if (estado) {
    return { content: 'Presentado', styles: { fillColor: [220, 252, 231], textColor: [22, 101, 52] } }; 
  } else {
    return { content: 'Pendiente', styles: { fillColor: [254, 243, 199], textColor: [146, 64, 14] } }; 
  }
};
    autoTable(doc, {
      startY: alturaActual + 6,
      theme: 'grid',
      head: [['Documento Requerido', 'Estado Actual']],
      headStyles: { fillColor: [147, 51, 234], textColor: [255, 255, 255], fontStyle: 'bold' }, // Púrpura de tu app
      bodyStyles: { textColor: [71, 85, 105] },
      styles: { lineColor: [220, 220, 220], lineWidth: 0.1 },
      body: [
        ['Constancia AFIP/ARCA', getEstadoData(op.docs_afip)],
        ['Alta Sistema Malvina', getEstadoData(op.docs_malvina)],
        ['Factura Comercial (USD)', getEstadoData(op.docs_factura)],
        ['Packing List', getEstadoData(op.docs_packing)],
        ['Certificado de Origen', getEstadoData(op.docs_origen)],
        ['Certificaciones Técnicas', getEstadoData(op.docs_tecnicas)],
        ['Carta Porte / CRT', getEstadoData(op.docs_transporte)],
      ],
    })

    // --- 5. DESCARGAR EL ARCHIVO CON NOMBRE AUTOMÁTICO PULIDO ---
    const fechaArchivo = new Date().toISOString().split('T')[0];
    const clienteArchivo = (op.cliente || 'CLIENTE').replace(/[^a-z0-9]/gi, '_').substring(0, 15);
    doc.save(`${fechaArchivo}_Proforma_${clienteArchivo}.pdf`);
  }

  if (cargando) {
    return <div className="p-8 text-center text-slate-500 font-bold">Cargando operaciones...</div>
  }

  return (
    <div className="min-h-screen bg-slate-50 p-4 md:p-8">
      <div className="max-w-6xl mx-auto">
        
        <div className="flex justify-between items-end mb-8">
          <div>
            <h1 className="text-3xl font-bold text-slate-900 mb-2">Operaciones</h1>
            <p className="text-slate-600 font-medium">Gestión de despachos activos</p>
          </div>
          <Link href="/operaciones/nueva" className="bg-purple-600 hover:bg-purple-700 text-white font-bold py-3 px-6 rounded-lg transition-all shadow-md">
            + Nueva Operación
          </Link>
        </div>

        <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
          <div className="overflow-x-auto">
            <table className="w-full text-left border-collapse">
              <thead>
                <tr className="bg-slate-100 border-b border-slate-200 text-slate-700">
                  <th className="p-4 font-bold text-sm">Fecha</th>
                  <th className="p-4 font-bold text-sm">Cliente</th>
                  <th className="p-4 font-bold text-sm">Tipo</th>
                  <th className="p-4 font-bold text-sm">Mercadería</th>
                  <th className="p-4 font-bold text-sm">Estado</th>
                  <th className="px-6 py-4 font-bold text-sm text-slate-700">Acciones</th>
                </tr>
              </thead>
              <tbody>
                {operaciones.length === 0 ? (
                  <tr>
                    <td colSpan={6} className="p-8 text-center text-slate-500 font-medium">
                      No hay operaciones registradas todavía.
                    </td>
                  </tr>
                ) : (
                  operaciones.map((op) => (
                    <tr key={op.id} className="border-b border-slate-100 hover:bg-slate-50 transition-colors">
                      <td className="p-4 text-sm text-slate-600">
                        {new Date(op.created_at).toLocaleDateString('es-AR')}
                      </td>
                      <td className="p-4 font-bold text-slate-900">{op.cliente}</td>
                      <td className="p-4">
                        <span className={`px-3 py-1 rounded-full text-xs font-bold ${
                          op.tipo === 'Importación' ? 'bg-blue-100 text-blue-700' : 'bg-orange-100 text-orange-700'
                        }`}>
                          {op.tipo}
                        </span>
                      </td>
                      <td className="p-4 text-sm text-slate-600 truncate max-w-xs">{op.producto}</td>
                      <td className="p-4">
                        <span className="px-3 py-1 rounded-full text-xs font-bold bg-yellow-100 text-yellow-800">
                          {op.estado || 'Pendiente'}
                        </span>
                      </td>
                      <td className="px-6 py-4">
                        <div className="flex gap-2">
                          
                          {/* BOTÓN: GENERAR PDF 📄 */}
                          <button 
                            onClick={() => generarPDF(op)}
                            className="p-2 text-slate-400 hover:text-blue-600 hover:bg-blue-50 rounded-lg transition-all" 
                            title="Descargar Proforma PDF"
                          >
                            📄
                          </button>

                         {/* Botón Editar (AHORA CONECTADO 🚀) */}
<Link 
  href={`/operaciones/editar/${op.id}`}
  className="p-2 text-slate-400 hover:text-purple-600 hover:bg-purple-50 rounded-lg transition-all flex items-center justify-center" 
  title="Editar Operación"
>
  ✏️
</Link>
                         
                          
                          {/* Botón Eliminar */}
                          <button 
                            onClick={() => eliminarOperacion(op.id)}
                            className="p-2 text-slate-400 hover:text-red-600 hover:bg-red-50 rounded-lg transition-all" 
                            title="Eliminar"
                          >
                            🗑️
                          </button>
                        </div>
                      </td>
                    </tr>
                  ))
                )}
              </tbody>
            </table>
          </div>
        </div>

      </div>
    </div>
  )
}